example.code:
variable "environment" {
  description = "Deployment environment (dev, staging, prod)"
  type        = string
  validation {
    condition     = contains(["dev", "staging", "prod"], var.environment)
    error_message = "Environment must be dev, staging, or prod."
  }
}

variable "db_password" {
  description = "Database master password"
  type        = string
  sensitive   = true
}

locals {
  name_prefix = "${var.project}-${var.environment}"
  common_tags = {
    Project     = var.project
    Environment = var.environment
    ManagedBy   = "terraform"
  }
  config = {
    dev     = { instance_type = "t3.micro",  multi_az = false }
    staging = { instance_type = "t3.small",  multi_az = false }
    prod    = { instance_type = "t3.medium", multi_az = true  }
  }[var.environment]
}

# Good: stable key, insert/remove safe
resource "aws_subnet" "private" {
  for_each = toset(var.availability_zones)
  vpc_id   = aws_vpc.main.id
  cidr_block = cidrsubnet(var.vpc_cidr, 8, index(var.availability_zones, each.key) + 10)
}

# Use dynamic blocks instead of copy-paste
dynamic "ingress" {
  for_each = var.ingress_rules
  content {
    from_port   = ingress.value.from_port
    to_port     = ingress.value.to_port
    protocol    = ingress.value.protocol
    cidr_blocks = ingress.value.cidr_blocks
  }
}

terraform {
  backend "s3" {
    bucket         = "company-terraform-state"
    key            = "project/env/terraform.tfstate"
    region         = "us-east-1"
    encrypt        = true
    dynamodb_table = "terraform-locks"
  }
}

# Bad: secret hardcoded in resource or tfvars
variable "db_password" {
  default = "supersecret123"
}
